import { useState, useEffect } from "react";

const IMG_WHOLE_6 = "data:image/jpeg;base64,";

const products = [
  {
    id: "slice_original",
    category: "切片戚風",
    name: "原味切片戚風",
    desc: "台灣雞蛋・零添加・當日現做",
    unit: "片",
    price: 55,
    minQty: 1,
    emoji: "🍰",
  },
  {
    id: "slice_matcha",
    category: "切片戚風",
    name: "抹茶切片戚風",
    desc: "日本抹茶粉・淡雅苦甘",
    unit: "片",
    price: 65,
    minQty: 1,
    emoji: "🍵",
  },
  {
    id: "slice_lemon",
    category: "切片戚風",
    name: "檸檬切片戚風",
    desc: "台灣檸檬・清爽酸香",
    unit: "片",
    price: 65,
    minQty: 1,
    emoji: "🍋",
  },
  {
    id: "whole_6",
    category: "整顆手工戚風",
    name: "6吋整顆戚風",
    desc: "約4–6人份・適合小聚",
    unit: "顆",
    price: 480,
    minQty: 1,
    emoji: "🎂",
    image: IMG_WHOLE_6,
  },
  {
    id: "whole_8",
    category: "整顆手工戚風",
    name: "8吋整顆戚風",
    desc: "約8–10人份・聚會首選",
    unit: "顆",
    price: 680,
    minQty: 1,
    emoji: "🎂",
  },
  {
    id: "cheese_classic",
    category: "古典乳酪蛋糕",
    name: "古典乳酪蛋糕（6吋）",
    desc: "濃郁紮實・奶香滿溢",
    unit: "顆",
    price: 520,
    minQty: 1,
    emoji: "🧀",
  },
  {
    id: "cheese_slice",
    category: "古典乳酪蛋糕",
    name: "乳酪蛋糕切片",
    desc: "單片享受・完整奶香",
    unit: "片",
    price: 90,
    minQty: 1,
    emoji: "🧀",
  },
];

const categories = [...new Set(products.map((p) => p.category))];

const CATEGORY_COLORS = {
  切片戚風: { bg: "#FEF3E2", accent: "#D4853A", light: "#FDF6EC" },
  整顆手工戚風: { bg: "#EDF7F0", accent: "#3A7D5A", light: "#F0FAF3" },
  古典乳酪蛋糕: { bg: "#F2EDF7", accent: "#7D5AA3", light: "#F8F5FC" },
};

export default function BakeryCalculator() {
  const [quantities, setQuantities] = useState({});
  const [note, setNote] = useState("");
  const [showSummary, setShowSummary] = useState(false);
  const [animate, setAnimate] = useState(false);

  const setQty = (id, val) => {
    const num = Math.max(0, parseInt(val) || 0);
    setQuantities((q) => ({ ...q, [id]: num }));
  };

  const increment = (id) => setQty(id, (quantities[id] || 0) + 1);
  const decrement = (id) => setQty(id, (quantities[id] || 0) - 1);

  const cartItems = products.filter((p) => (quantities[p.id] || 0) > 0);
  const total = cartItems.reduce((sum, p) => sum + p.price * quantities[p.id], 0);
  const itemCount = cartItems.reduce((sum, p) => sum + quantities[p.id], 0);

  useEffect(() => {
    if (total > 0) {
      setAnimate(true);
      const t = setTimeout(() => setAnimate(false), 300);
      return () => clearTimeout(t);
    }
  }, [total]);

  const reset = () => {
    setQuantities({});
    setNote("");
    setShowSummary(false);
  };

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(135deg, #FDF8F2 0%, #F9F0E4 50%, #FDF6EC 100%)",
      fontFamily: "'Georgia', 'Noto Serif TC', serif",
      padding: "0 0 80px 0",
    }}>
      {/* Header */}
      <div style={{
        background: "#3D2314",
        padding: "32px 24px 24px",
        textAlign: "center",
        position: "relative",
        overflow: "hidden",
      }}>
        <div style={{
          position: "absolute", inset: 0,
          backgroundImage: "radial-gradient(circle at 20% 50%, rgba(196,133,74,0.15) 0%, transparent 60%), radial-gradient(circle at 80% 50%, rgba(196,133,74,0.1) 0%, transparent 60%)",
        }} />
        <div style={{ position: "relative", zIndex: 1 }}>
          <div style={{ fontSize: 13, letterSpacing: 4, color: "#C4854A", marginBottom: 8, textTransform: "uppercase" }}>
            嘉義 · 手工烘焙
          </div>
          <h1 style={{ margin: 0, fontSize: 28, fontWeight: 700, color: "#FDF6EC", lineHeight: 1.3 }}>
            訂購報價計算器
          </h1>
          <p style={{ margin: "8px 0 0", fontSize: 14, color: "#C8A882", letterSpacing: 1 }}>
            選好品項與數量，立即看到報價
          </p>
        </div>
      </div>

      {/* Floating total bar */}
      {total > 0 && (
        <div style={{
          position: "sticky", top: 0, zIndex: 100,
          background: "#C4854A",
          padding: "12px 24px",
          display: "flex", justifyContent: "space-between", alignItems: "center",
          boxShadow: "0 4px 20px rgba(61,35,20,0.2)",
          transition: "all 0.3s",
          transform: animate ? "scale(1.01)" : "scale(1)",
        }}>
          <span style={{ color: "#FDF6EC", fontSize: 14, fontWeight: 600 }}>
            共 {itemCount} 件商品
          </span>
          <span style={{ color: "#FDF6EC", fontSize: 20, fontWeight: 700, letterSpacing: 1 }}>
            NT$ {total.toLocaleString()}
          </span>
        </div>
      )}

      <div style={{ maxWidth: 640, margin: "0 auto", padding: "0 16px" }}>

        {/* Product sections */}
        {categories.map((cat) => {
          const col = CATEGORY_COLORS[cat];
          const catProducts = products.filter((p) => p.category === cat);
          return (
            <div key={cat} style={{ marginTop: 28 }}>
              <div style={{
                display: "flex", alignItems: "center", gap: 10, marginBottom: 14,
              }}>
                <div style={{
                  width: 4, height: 24, borderRadius: 2,
                  background: col.accent,
                }} />
                <h2 style={{ margin: 0, fontSize: 17, fontWeight: 700, color: "#3D2314", letterSpacing: 1 }}>
                  {cat}
                </h2>
              </div>

              <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
                {catProducts.map((p) => {
                  const qty = quantities[p.id] || 0;
                  const isSelected = qty > 0;
                  return (
                    <div key={p.id} style={{
                      background: isSelected ? col.bg : "#fff",
                      border: `1.5px solid ${isSelected ? col.accent : "#EDE0D0"}`,
                      borderRadius: 16,
                      padding: "16px 18px",
                      display: "flex", alignItems: "center", gap: 14,
                      transition: "all 0.25s",
                      boxShadow: isSelected ? `0 4px 16px ${col.accent}22` : "0 1px 4px rgba(61,35,20,0.06)",
                    }}>
                      <div style={{
                        width: 48, height: 48, borderRadius: 12,
                        background: col.light,
                        display: "flex", alignItems: "center", justifyContent: "center",
                        fontSize: 26, flexShrink: 0,
                        border: `1px solid ${col.accent}33`,
                        overflow: "hidden",
                      }}>
                        {p.image ? (
                          <img src={p.image} alt={p.name} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                        ) : p.emoji}
                      </div>

                      <div style={{ flex: 1, minWidth: 0 }}>
                        <div style={{ fontWeight: 700, fontSize: 15, color: "#3D2314", lineHeight: 1.3 }}>
                          {p.name}
                        </div>
                        <div style={{ fontSize: 12, color: "#9A7860", marginTop: 2 }}>{p.desc}</div>
                        <div style={{ fontSize: 14, fontWeight: 700, color: col.accent, marginTop: 4 }}>
                          NT$ {p.price.toLocaleString()} <span style={{ fontSize: 12, fontWeight: 400, color: "#9A7860" }}>/ {p.unit}</span>
                        </div>
                      </div>

                      {/* Quantity control */}
                      <div style={{ display: "flex", alignItems: "center", gap: 8, flexShrink: 0 }}>
                        <button onClick={() => decrement(p.id)} style={{
                          width: 32, height: 32, borderRadius: 10,
                          border: `1.5px solid ${qty > 0 ? col.accent : "#D9CCBD"}`,
                          background: qty > 0 ? col.accent : "#F5EDE2",
                          color: qty > 0 ? "#fff" : "#B0977C",
                          fontSize: 18, lineHeight: 1, cursor: "pointer",
                          display: "flex", alignItems: "center", justifyContent: "center",
                          transition: "all 0.2s", fontFamily: "inherit",
                        }}>−</button>

                        <span style={{
                          width: 28, textAlign: "center",
                          fontWeight: 700, fontSize: 16, color: "#3D2314",
                        }}>
                          {qty}
                        </span>

                        <button onClick={() => increment(p.id)} style={{
                          width: 32, height: 32, borderRadius: 10,
                          border: `1.5px solid ${col.accent}`,
                          background: col.accent,
                          color: "#fff",
                          fontSize: 18, lineHeight: 1, cursor: "pointer",
                          display: "flex", alignItems: "center", justifyContent: "center",
                          transition: "all 0.2s", fontFamily: "inherit",
                        }}>+</button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          );
        })}

        {/* Note field */}
        <div style={{ marginTop: 28 }}>
          <label style={{ fontSize: 14, fontWeight: 700, color: "#3D2314", letterSpacing: 1, display: "block", marginBottom: 8 }}>
            備註 / 特殊需求
          </label>
          <textarea
            value={note}
            onChange={(e) => setNote(e.target.value)}
            placeholder="例如：需要禮盒包裝、指定取貨日期、口味客製化需求…"
            rows={3}
            style={{
              width: "100%", boxSizing: "border-box",
              border: "1.5px solid #EDE0D0", borderRadius: 12,
              padding: "12px 14px", fontSize: 14, color: "#3D2314",
              background: "#fff", resize: "vertical",
              fontFamily: "inherit", outline: "none",
              lineHeight: 1.6,
            }}
          />
        </div>

        {/* Summary / Quote */}
        {total > 0 && (
          <div style={{
            marginTop: 28,
            background: "#3D2314",
            borderRadius: 20,
            padding: "24px 22px",
            boxShadow: "0 8px 32px rgba(61,35,20,0.18)",
          }}>
            <div style={{ fontSize: 13, color: "#C4854A", letterSpacing: 3, marginBottom: 16, textTransform: "uppercase" }}>
              報價明細
            </div>

            {cartItems.map((p) => (
              <div key={p.id} style={{
                display: "flex", justifyContent: "space-between",
                alignItems: "center",
                padding: "8px 0",
                borderBottom: "1px solid rgba(196,133,74,0.2)",
              }}>
                <div>
                  <span style={{ color: "#FDF6EC", fontSize: 14, fontWeight: 600 }}>{p.name}</span>
                  <span style={{ color: "#C8A882", fontSize: 13, marginLeft: 8 }}>× {quantities[p.id]} {p.unit}</span>
                </div>
                <span style={{ color: "#C4854A", fontWeight: 700, fontSize: 15 }}>
                  NT$ {(p.price * quantities[p.id]).toLocaleString()}
                </span>
              </div>
            ))}

            {note && (
              <div style={{ marginTop: 12, padding: "10px 14px", background: "rgba(196,133,74,0.1)", borderRadius: 10 }}>
                <div style={{ fontSize: 12, color: "#C4854A", marginBottom: 4 }}>備註</div>
                <div style={{ fontSize: 13, color: "#C8A882", lineHeight: 1.5 }}>{note}</div>
              </div>
            )}

            <div style={{
              display: "flex", justifyContent: "space-between", alignItems: "center",
              marginTop: 18, paddingTop: 18,
              borderTop: "1.5px solid #C4854A",
            }}>
              <span style={{ fontSize: 16, fontWeight: 700, color: "#FDF6EC", letterSpacing: 1 }}>合計金額</span>
              <span style={{ fontSize: 26, fontWeight: 700, color: "#C4854A", letterSpacing: 1 }}>
                NT$ {total.toLocaleString()}
              </span>
            </div>

            <p style={{ margin: "14px 0 0", fontSize: 12, color: "#9A7860", lineHeight: 1.7 }}>
              ＊以上為參考報價，實際金額依訂單確認為準。<br />
              ＊建議提前 2–3 天預訂，確保新鮮現做。
            </p>
          </div>
        )}

        {/* Actions */}
        <div style={{ display: "flex", gap: 12, marginTop: 20 }}>
          {total > 0 && (
            <button
              onClick={() => {
                const lines = cartItems.map(p => `${p.name} × ${quantities[p.id]} ${p.unit}＝NT$${(p.price * quantities[p.id]).toLocaleString()}`).join("\n");
                const text = `【訂購報價單】\n${lines}\n${note ? `備註：${note}\n` : ""}合計：NT$${total.toLocaleString()}`;
                navigator.clipboard?.writeText(text);
                alert("報價單已複製！可直接貼到 LINE / 訊息傳送給客戶 ✓");
              }}
              style={{
                flex: 2,
                padding: "16px", borderRadius: 14,
                background: "#C4854A", border: "none",
                color: "#fff", fontSize: 16, fontWeight: 700,
                cursor: "pointer", letterSpacing: 1,
                fontFamily: "inherit",
                boxShadow: "0 4px 16px rgba(196,133,74,0.35)",
              }}
            >
              📋 複製報價單
            </button>
          )}
          <button
            onClick={reset}
            style={{
              flex: 1,
              padding: "16px", borderRadius: 14,
              background: "transparent",
              border: "1.5px solid #D4B896",
              color: "#9A7860", fontSize: 15, fontWeight: 600,
              cursor: "pointer", letterSpacing: 1,
              fontFamily: "inherit",
            }}
          >
            重新填寫
          </button>
        </div>

      </div>
    </div>
  );
}
